from appwrite.client import Client
from appwrite.services.functions import Functions
import json

# 1. Initialize the Client
client = Client()
client.set_endpoint('https://sgp.cloud.appwrite.io/v1') # Your API Endpoint
client.set_project('6999dd6d002cd940c068')               # Your Project ID
client.set_key('standard_f521b3b7cd35fb27980d8baba62674e67309e8cb93b5fcdc1d239126f0a61ed4a679078c86f85fcc5c897ab2422fde2fc40184be1aed15466867db7006e8143fe83b8d837dcbb417740e8eb95e73cfa2b2f7d4f9a444262aa8cd8061a2418dfe59355ffc897e3635f4dd5d771fdacda0f27b00b6d8ce207fb7aa58ed3d981964')                     # Your API Key (Server SDK)

# 2. Initialize the Functions service
functions = Functions(client)

# 3. Define your payload (matching what your function expects)
payload = {
  "imageBase64": "data:image/webp;base64,",
}

# 4. Create the execution
# async=False means the code waits for the result (synchronous)
result = functions.create_execution(
    function_id='6999e00d0005134cf882',
    body=json.dumps(payload),
    xasync=False 
)

# 5. View the output
print(f"Status: {result['status']}")
print(f"Response Body: {result['responseBody']}")
print(f"Logs: {result['logs']}")
